const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const session = require('express-session');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const sessionMiddleware = session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: false } // Set to true if using HTTPS
});

app.use(sessionMiddleware);

io.use((socket, next) => {
  sessionMiddleware(socket.request, socket.request.res || {}, next);
});

const users = {}; // Store users and their scores

io.on('connection', (socket) => {
  console.log('New client connected');

  socket.on('authenticate', (data) => {
    const { username } = data;
    if (username) {
      const sessionId = crypto.randomBytes(16).toString('hex');
      socket.request.session.userId = sessionId;
      users[sessionId] = { username, score: 0 };
      socket.emit('authenticated', { success: true, sessionId });
    } else {
      socket.emit('authenticated', { success: false, message: 'Invalid username' });
    }
  });

  socket.on('submitScore', (data) => {
    const { sessionId, score } = data;
    if (users[sessionId]) {
      users[sessionId].score = score;
      io.emit('updateLeaderboard', users);
    } else {
      socket.emit('error', { message: 'Invalid session' });
    }
  });

  socket.on('disconnect', () => {
    console.log('Client disconnected');
  });
});

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});